-- 0267. auto-tag 추천 큐레이션 플래그 is_recommendable (L2-4 B안)
--
-- 목적: 회원 글쓰기 무료 자동태깅(auto-tag)이 DB 전체(2085)가 아닌 '검증된 추천 태그'만
--   후보로 쓰도록. OLD 큐레이션 사전 819개를 3단계 병합 반영해 현재 ko로 매핑 → 804개 시드(true).
--   나머지(자동등록·온보딩 일반어 등)는 false → 자동추천 노이즈 차단. 신규 태그 기본 false.
-- 누락 3건(RF·마리오네트·민감피부)은 시드 대표어(고주파·마리오네트주름·민감성피부)의 alias →
--   텍스트 매칭 시 대표어로 정규화되어 커버리지 손실 없음.

ALTER TABLE public.tag_dictionary ADD COLUMN IF NOT EXISTS is_recommendable boolean NOT NULL DEFAULT false;

UPDATE public.tag_dictionary SET is_recommendable = true
